    sse_encode_String(self.packageId, serializer);
    sse_encode_String(self.version, serializer);
    sse_encode_String(self.type, serializer);
    sse_encode_String(self.fileName, serializer);
    sse_encode_String(self.sha1, serializer);
    sse_encode_String(self.sha256, serializer);
    sse_encode_u_64(self.size, serializer);
    sse_encode_String(self.notesMarkdown, serializer);
    sse_encode_String(self.notesHtml, serializer);
  }

  @protected
  void sse_encode_i_32(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putInt32(self);
  }
}
